// worker1.js - Public-facing worker
export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    
    if (url.pathname.startsWith('/api/')) {
      // Forward to internal worker
      const response = await env.WORKER2.fetch(request);
      return response;
    }
    
    return new Response('Public Worker Ready', { status: 200 });
  }
};

